+/// Convenience function for simple training
+pub fn trainSimple(
+    allocator: std.mem.Allocator,
+    model_path: []const u8,
+    output_path: []const u8,
+    data_source: union(enum) {
+        jsonl: []const u8,
+        repo: []const u8,
+    },
+    options: struct {
+        epochs: u32 = 3,
+        learning_rate: f32 = 1e-4,
+        lora_rank: u32 = 16,
+    },
+) !void {
+    var interrupt = std.atomic.Value(bool).init(true);
+
+    var config = Trainer.Config{
+        .model_path = model_path,
+        .output_path = output_path,
+        .epochs = options.epochs,
+        .learning_rate = options.learning_rate,
+        .lora_rank = options.lora_rank,
+    };
+
+    switch (data_source) {
+        .jsonl => |path| config.data_jsonl_path = path,
+        .repo => |path| config.data_from_repo = path,
+    }
+
+    var trainer = try Trainer.init(allocator, config, &interrupt);
+    defer trainer.deinit();
+
+    try trainer.loadData();
+    try trainer.train();
+}
