+/// DataLoader for streaming large datasets (Lance integration ready)
+pub const DataLoader = struct {
+    allocator: std.mem.Allocator,
+    source_path: []const u8,
+    batch_size: usize,
+    current_offset: usize,
+    total_size: usize,
+
+    // For Lance integration
+    lance_handle: ?*anyopaque,
+
+    pub fn init(allocator: std.mem.Allocator, source_path: []const u8, batch_size: usize) !DataLoader {
+        // Get file size for progress tracking
+        const file = try std.fs.cwd().openFile(source_path, .{});
+        defer file.close();
+        const stat = try file.stat();
+
+        return .{
+            .allocator = allocator,
+            .source_path = try allocator.dupe(u8, source_path),
+            .batch_size = batch_size,
+            .current_offset = 0,
+            .total_size = stat.size,
+            .lance_handle = null, // Future: Lance integration
+        };
+    }
+
+    pub fn deinit(self: *DataLoader) void {
+        self.allocator.free(self.source_path);
+    }
+
+    /// Get next batch of training examples
+    pub fn nextBatch(self: *DataLoader) !?[][]const u8 {
+        if (self.current_offset >= self.total_size) {
+            return null; // End of data
+        }
+
+        var batch = std.ArrayList([]const u8).init(self.allocator);
+        errdefer {
+            for (batch.items) |item| self.allocator.free(item);
+            batch.deinit();
+        }
+
+        const file = try std.fs.cwd().openFile(self.source_path, .{});
+        defer file.close();
+
+        try file.seekTo(self.current_offset);
+
+        var line_buf: [64 * 1024]u8 = undefined;
+        var reader = file.reader();
+
+        while (batch.items.len < self.batch_size) {
+            const line = reader.readUntilDelimiter(&line_buf, '\n') catch |err| switch (err) {
+                error.EndOfStream => break,
+                else => return err,
+            };
+
+            if (line.len == 0) continue;
+
+            const parsed = std.json.parseFromSlice(
+                struct { text: []const u8 },
+                self.allocator,
+                line,
+                .{},
+            ) catch continue;
+            defer parsed.deinit();
+
+            const text_copy = try self.allocator.dupe(u8, parsed.value.text);
+            try batch.append(text_copy);
+
+            self.current_offset = @intCast(try file.getPos());
+        }
+
+        if (batch.items.len == 0) {
+            return null;
+        }
+
+        return try batch.toOwnedSlice();
+    }
+
+    /// Reset to beginning
+    pub fn reset(self: *DataLoader) void {
+        self.current_offset = 0;
+    }
+
+    /// Get progress (0.0 - 1.0)
+    pub fn progress(self: *DataLoader) f32 {
+        if (self.total_size == 0) return 1.0;
+        return @as(f32, @floatFromInt(self.current_offset)) / @as(f32, @floatFromInt(self.total_size));
+    }
+};
